    ) -> None:
        """Failsafe check for workers with very stale heartbeats."""
        now = datetime.now(timezone.utc)
        stale_workers: List[DerivedWorkerState] = []

        for ws in worker_states:
            if ws.is_terminal:
                continue

            if ws.in_startup_phase:
